                    prcj = opj_uint_floordivpow2(opj_uint64_ceildiv_res_uint32((OPJ_UINT64)pi->y,
                                                 ((OPJ_UINT64)comp->dy << levelno)), res->pdy)
                           - opj_uint_floordivpow2(try0, res->pdy);
